#define LIMIT -999

#include <stdlib.h>
#include <stdio.h>
#include <string.h>
#include <math.h>
#include <sys/time.h>

#define BLOCK_SIZE 16

__device__ int maximum(int a, int b, int c) {
    int k;
    if (a <= b)
        k = b;
    else
        k = a;

    if (k <= c)
        return c;
    else
        return k;
}

__global__ void nw_kernel(int *input_itemsets, int *referrence, int max_cols, int blk, int penalty, int max_blocks) {
    int b_index_x = blockIdx.x * blockDim.x + threadIdx.x;
    if (b_index_x >= blk) return;

    int b_index_y = blk - 1 - b_index_x;

    int input_itemsets_l[(BLOCK_SIZE + 1) * (BLOCK_SIZE + 1)];
    int reference_l[BLOCK_SIZE * BLOCK_SIZE];

    // Load reference_l
    for (int i = 0; i < BLOCK_SIZE; ++i) {
        #pragma unroll
        for (int j = 0; j < BLOCK_SIZE; ++j) {
            reference_l[i * BLOCK_SIZE + j] = referrence[max_cols * (b_index_y * BLOCK_SIZE + i + 1) + b_index_x * BLOCK_SIZE + j + 1];
        }
    }

    // Load input_itemsets_l
    for (int i = 0; i < BLOCK_SIZE + 1; ++i) {
        #pragma unroll
        for (int j = 0; j < BLOCK_SIZE + 1; ++j) {
            input_itemsets_l[i * (BLOCK_SIZE + 1) + j] = input_itemsets[max_cols * (b_index_y * BLOCK_SIZE + i) + b_index_x * BLOCK_SIZE + j];
        }
    }

    // Compute
    for (int i = 1; i < BLOCK_SIZE + 1; ++i) {
        for (int j = 1; j < BLOCK_SIZE + 1; ++j) {
            input_itemsets_l[i * (BLOCK_SIZE + 1) + j] = maximum(
                input_itemsets_l[(i - 1) * (BLOCK_SIZE + 1) + j - 1] + reference_l[(i - 1) * BLOCK_SIZE + j - 1],
                input_itemsets_l[i * (BLOCK_SIZE + 1) + j - 1] - penalty,
                input_itemsets_l[(i - 1) * (BLOCK_SIZE + 1) + j] - penalty);
        }
    }

    // Store back
    for (int i = 0; i < BLOCK_SIZE; ++i) {
        #pragma unroll
        for (int j = 0; j < BLOCK_SIZE; ++j) {
            input_itemsets[max_cols * (b_index_y * BLOCK_SIZE + i + 1) + b_index_x * BLOCK_SIZE + j + 1] = input_itemsets_l[(i + 1) * (BLOCK_SIZE + 1) + j + 1];
        }
    }
}

__global__ void nw_kernel_bottom(int *input_itemsets, int *referrence, int max_cols, int blk, int penalty, int max_blocks) {
    int b_index_x = blockIdx.x * blockDim.x + threadIdx.x;
    if (b_index_x < blk - 1) return;
    if (b_index_x >= max_blocks) return;

    int b_index_y = max_blocks + blk - 2 - b_index_x;

    int input_itemsets_l[(BLOCK_SIZE + 1) * (BLOCK_SIZE + 1)];
    int reference_l[BLOCK_SIZE * BLOCK_SIZE];

    // Load reference_l
    for (int i = 0; i < BLOCK_SIZE; ++i) {
        #pragma unroll
        for (int j = 0; j < BLOCK_SIZE; ++j) {
            reference_l[i * BLOCK_SIZE + j] = referrence[max_cols * (b_index_y * BLOCK_SIZE + i + 1) + b_index_x * BLOCK_SIZE + j + 1];
        }
    }

    // Load input_itemsets_l
    for (int i = 0; i < BLOCK_SIZE + 1; ++i) {
        #pragma unroll
        for (int j = 0; j < BLOCK_SIZE + 1; ++j) {
            input_itemsets_l[i * (BLOCK_SIZE + 1) + j] = input_itemsets[max_cols * (b_index_y * BLOCK_SIZE + i) + b_index_x * BLOCK_SIZE + j];
        }
    }

    // Compute
    for (int i = 1; i < BLOCK_SIZE + 1; ++i) {
        for (int j = 1; j < BLOCK_SIZE + 1; ++j) {
            input_itemsets_l[i * (BLOCK_SIZE + 1) + j] = maximum(
                input_itemsets_l[(i - 1) * (BLOCK_SIZE + 1) + j - 1] + reference_l[(i - 1) * BLOCK_SIZE + j - 1],
                input_itemsets_l[i * (BLOCK_SIZE + 1) + j - 1] - penalty,
                input_itemsets_l[(i - 1) * (BLOCK_SIZE + 1) + j] - penalty);
        }
    }

    // Store back
    for (int i = 0; i < BLOCK_SIZE; ++i) {
        #pragma unroll
        for (int j = 0; j < BLOCK_SIZE; ++j) {
            input_itemsets[max_cols * (b_index_y * BLOCK_SIZE + i + 1) + b_index_x * BLOCK_SIZE + j + 1] = input_itemsets_l[(i + 1) * (BLOCK_SIZE + 1) + j + 1];
        }
    }
}

void nw_optimized(int *input_itemsets, int *output_itemsets, int *referrence,
        int max_rows, int max_cols, int penalty)
{
    int max_blocks = (max_cols - 1) / BLOCK_SIZE;

    // Process top-left matrix
    for (int blk = 1; blk <= max_blocks; blk++) {
        int threads = 256;
        int blocks = (blk + threads - 1) / threads;
        nw_kernel<<<blocks, threads>>>(input_itemsets, referrence, max_cols, blk, penalty, max_blocks);
        cudaDeviceSynchronize();
    }

    printf("Processing bottom-right matrix\n");

    for (int blk = 2; blk <= max_blocks; blk++) {
        int threads = 256;
        int blocks = (max_blocks + threads - 1) / threads;
        nw_kernel_bottom<<<blocks, threads>>>(input_itemsets, referrence, max_cols, blk, penalty, max_blocks);
        cudaDeviceSynchronize();
    }
}

void runTest(int argc, char** argv);

int main(int argc, char** argv)
{
    runTest(argc, argv);
    return EXIT_SUCCESS;
}

